import { createSlice } from '@reduxjs/toolkit'
import axios from 'axios'


export const orderCreateSlice = createSlice({
    name: 'orderCreate',
    initialState: {},
    reducers: {
        orderCreateRequest: (state) => { 
            state.loading = true;
        },
        orderCreateSuccess: (state, action) => { 
            state.loading = false;
            state.success = true;
            state.order = action.payload; 
        },
        orderCreateFail: (state, action) => { 
            state.loading = false; 
            state.error = action.payload;
        },
        orderCreateReset: (state, action) => { 
            Object.assign(state, {})
        },
    }
})
export const { orderCreateRequest, orderCreateSuccess, orderCreateFail } = orderCreateSlice.actions
export default orderCreateSlice.reducer;


// thunk function to fetch the product details
export const createOrder = (order) => async (dispatch, getState) => {
    try{
        dispatch(orderCreateRequest());

        const { userLogin: { userInfo }} = getState()

        const headers = {
            'Content-Type': 'application/json',
            Authorization: `Bearer ${userInfo.token}`
        }

        const { data } = await axios.post(
            'api/orders/add/',
            order,
            { headers: headers }
            )

        dispatch(orderCreateSuccess(data));

    } catch (error) {
        const msg = (error.response && error.response.data.detail ? error.response.data.detail : error.message)
        dispatch(orderCreateFail(msg))
    }
}
